SELECT COUNT(*)
FROM sagas
WHERE user_id = #{userId}

SELECT DISTINCT type
FROM sagas
WHERE user_id = #{userId}

SELECT COUNT(*)
FROM sagas
WHERE user_id = #{userId}
  AND type = #{type}
  AND status = 'COMPLETED'

SELECT COUNT(*)
FROM sagas
WHERE user_id = #{userId}
  AND rarity = #{rarity}
